import torch
import torch.nn as nn
import torch.optim as optim
from torch.utils.data import DataLoader, Dataset
import requests
from io import BytesIO

# Custom Dataset Example
class CustomDataset(Dataset):
    def __init__(self, data, labels):
        self.data = data
        self.labels = labels

    def __len__(self):
        return len(self.data)

    def __getitem__(self, idx):
        return self.data[idx], self.labels[idx]

# Securely download model checkpoint
def download_model(url, allowed_domains):
    if not any(url.startswith(domain) for domain in allowed_domains):
        raise ValueError("URL not allowed")
    response = requests.get(url, timeout=10)
    response.raise_for_status()
    return BytesIO(response.content)

# Load model checkpoint
def load_model_from_url(url, allowed_domains):
    model_bytes = download_model(url, allowed_domains)
    model = torch.load(model_bytes, map_location=torch.device('cpu'))
    return model

# Fine-tune model
def fine_tune_model(model, train_loader, num_epochs=5, learning_rate=0.001):
    criterion = nn.CrossEntropyLoss()
    optimizer = optim.Adam(model.parameters(), lr=learning_rate)

    model.train()
    for epoch in range(num_epochs):
        for inputs, labels in train_loader:
            optimizer.zero_grad()
            outputs = model(inputs)
            loss = criterion(outputs, labels)
            loss.backward()
            optimizer.step()

# Example usage
